import React from 'react';
import PropTypes from 'prop-types';
import {
    Container, Form, Button,
    Row, Col,

} from 'react-bootstrap';
// const config = require('./config.js');
import { DataContext } from '../data-context';
import Select from "react-select"; // https://github.com/JedWatson/react-select
import packageJson from '../../package.json';

const apiUrl = process.env.REACT_APP_API_URL;
const forge = require('node-forge');

export default class LogIn extends React.Component {
    static contextType = DataContext;
    static propTypes = {
        onLoginSuccess: PropTypes.func,
        onLoginFailure: PropTypes.func,
    };

    // ::: ทดลอง Demo Staff User :::
    // email: mchayapol@gmail.com
    // password: aaa

    constructor(...args) {
        super(...args);
        if (process.env.NODE_ENV === 'development') {
            this.state = {
                userCode: '10314',
                password: 'aaa',
                lines: [],
                code: '',
                lineOption: {},
            }
        } else {
            this.state = {
                userCode: '',
                password: '',
                lines: [],
                code: '',
                lineOption: {},
            }
        }
    }

    UNSAFE_componentWillMount() {

    }

    handleLineSelect = (selectedOption) => {
        console.log("line", selectedOption.value)
        this.setState({
            lineOption: selectedOption
        })
    }


    handleChange = (e) => {
        this.setState({
            [e.target.id]: e.target.value
        });
    }

    handleLogIn = (e) => {
        // console.log(config)
        // e.preventDefault();

        let userCode = this.state.userCode;
        let md = forge.md.sha256.create();
        md.update(this.state.password);
        let password = md.digest().toHex();

        console.log(userCode, password)
        let isOk = false;
        let users = this.context.users;
        let u = null;
        for (let i = 0; i < users.length; i++) {
            u = users[i]
            // if (u.code === userCode && u.password === password) {
            console.log(u.code, userCode)
            if (u.code === userCode) {
                isOk = true;
                break;
            }
        }

        if (isOk) {
            this.props.onLoginSuccess(u);
        } else {
            this.props.onLoginFailure();
        }


    }

    handleLaunch = () => {
        if (!this.state.lineOption.value) return;
        let name = this.state.lineOption.value;
        let code = this.state.code;

        let lines = this.context.lines;
        let found = false;
        let line;
        for (let i = 0; i < lines.length; i++) {
            line = lines[i];
            if (line.name == name && line.code == code) {
                found = true;
                console.log('Found!!!')
                break;
            }
        }

        if (found && line) {
            console.log("Success")
            this.props.onLineSelected(line)
        } else {
            console.log("Fail")
            // do nothing
        }
    }

    render() {
        let lines = []
        this.context.lines.forEach(v => {
            lines.push({
                value: v.name,
                label: v.name
            })
        })


        // this.setState({
        //     lines: lines,
        // })


        return (
            <Container fluid>
                <Row className="justify-content-md-center"
                    style={{
                        height: '100vh',
                        width: '100%',
                        left: 0,
                        padding: 0
                    }}>
                    <Col sm={6} style={{
                        // backgroundImage: 'url(https://source.unsplash.com/random)',
                        // backgroundImage: 'url(https://source.unsplash.com/collection/8443373/inventory)',
                        backgroundImage: 'url(https://source.unsplash.com/collection/9266271/mechanical-machine-repair)',
                        backgroundRepeat: 'no-repeat',
                        backgroundSize: 'cover',
                        backgroundPosition: 'center',
                    }}>
                    </Col>
                    <Col sm={6} style={{ color: '#eeeeee' }}>
                        <h2 style={{ color: '#eeee33' }}>Honda Lock: Repair Request System</h2>
                        <span style={{color: '#a0a0a0'}}>Version: {packageJson.version}-{process.env.NODE_ENV}</span>
                        <hr style={{ borderTop: "1px dotted white" }} />
                        <h3>Access Request Dashboard</h3>
                        <Form.Group as={Row}>
                            <Col md={1}>Line</Col>
                            <Col style={{ color: '#000000' }}>
                                <Select
                                    // styles={{ color: '#000000' }}
                                    value={this.state.lineOption}
                                    options={lines}
                                    menuColor='red'
                                    onChange={this.handleLineSelect} />
                            </Col>
                        </Form.Group>
                        <Form.Group as={Row}>
                            <Col md={1}>Code</Col>
                            <Col >
                                <Form.Control
                                    id="code"
                                    type="password"
                                    placeholder="Line Code"
                                    value={this.state.code}
                                    onChange={this.handleChange} />
                            </Col>
                        </Form.Group>
                        <Form.Group>
                            <Button block variant="success" onClick={this.handleLaunch}>Launch</Button>
                        </Form.Group>

                        <hr style={{ borderTop: "1px dotted white" }} />
                        <h3>Management Login</h3>
                        <Form.Group as={Row}>
                            <Col md={1}>Code</Col>
                            <Col>
                                <Form.Control id="userCode" type="text" placeholder="User Code" value={this.state.userCode} onChange={this.handleChange} />
                            </Col>
                        </Form.Group>
                        <Form.Group as={Row}>
                            <Col md={1}>Password</Col>
                            <Col>
                                <Form.Control id="password" type="password" placeholder="Password" value={this.state.password} onChange={this.handleChange} />
                            </Col>
                        </Form.Group>
                        <Button block variant="success" onClick={this.handleLogIn}>Log In</Button>

                    </Col>
                </Row>
            </Container >
        );
    }
}

