export function getDurationTimeInMinuteText(ms) {
    return `${Math.floor(moment.duration(ms).asMinutes())} minutes`;
}

export function getDurationTimeText(ms, includeSeconds = false) {
    let d = moment.duration(ms);
    if (d.isValid()) {
        let format = includeSeconds ? ":mm:ss" : ":mm";
        return Math.floor(d.asHours()) + moment.utc(d.as('ms')).format(format);
    } else {
        return '-';
    }
}

export function getDateText(ms) {
    let d = moment(ms);
    if (d.isValid())
        return d.format('DD-MM-YYYY (HH:mm)')
    else
        return '-';
}