    handleAdd = (e) => {
        let code = this.state.code;
        let name = this.state.name;
        let lines = this.state.lines;

        // Confirm that there's no existing code
        for (let i = 0; i < lines.length; i++) {
            let u = lines[i]
            if (code === u.code) {
                alert('มีรหัสผู้ใช้นี้อยู่แล้ว')
                return
            }
        }

        util.saveLine({
            code: code,
            name: name
        }).then(res => {
            alert(`เพิ่มข้อมูลผู้ใช้ใหม่แล้ว ${code} ${name}`)
            util.fetchLines().then(res => {
                let lines = res.data
                this.context.lines = lines
                this.setState({
                    lines: lines
                })
            })
        }).catch(err => {
            alert('เกิดความผิดพลาดในการเพิ่มข้อมูล\n' + err)
            console.error(err)
        })

        this.setState({
            _id: '',
            code: '',
            name: '',
            modeAdd: false,
        })
    }

