import React from 'react';
import PropTypes from 'prop-types';
import {
    Container, Form,
    ButtonGroup, Button,
    Row, Col,

} from 'react-bootstrap';
import { DataContext } from '../data-context';


export default class CodeLoginForm extends React.Component {
    static contextType = DataContext;

    static propTypes = {
        handleLoginSuccess: PropTypes.func,
        handleLoginFailure: PropTypes.func,
    };

    constructor(...args) {
        super(...args);
        if (process.env.NODE_ENV === 'development') {
            this.state = {
                code: '10314',  // dev
                teamCode: 'doraemon'
            }
        } else {
            this.state = {
                code: '10314',
                teamCode: 'doraemon'
            }

        }
    }

    handleChange = (e) => {
        this.setState({
            [e.target.id]: e.target.value
        });
    }

    handleSubmit = (e) => {
        // console.log(config)
        e.preventDefault();

        let users = this.context.users;
        let found = false;
        let theUser = null;
        // console.log(this.state.code, users.length)
        if (this.state.teamCode !== process.env.REACT_APP_TEAM_CODE) {
            this.props.handleUserVerificationFailure()
            return
        }

        for (let i = 0; i < users.length; i++) {
            if (users[i].code === this.state.code) {
                found = true;
                theUser = users[i];
                break;
            }
        }

        console.log('found', found);
        if (found) {
            this.props.handleUserVerificationSuccess(theUser);
        } else {
            this.props.handleUserVerificationFailure();
        }
    }

    addCode = (code) => {
        if (code === -1) {
            this.setState({ code: this.state.code.slice(0, -1) });

        } else {
            this.setState({ code: this.state.code + code });
        }
    }
    render() {
        return (
            <DataContext.Provider value={this.context}>
                <Container>
                    <Form onSubmit={this.handleSubmit}>
                        {/* 
                        <Row className="justify-content-md-center">
                            <Form.Group controlId="code">
                                <Form.Control
                                    name="email"
                                    type="text"
                                    placeholder="Code"
                                    value={this.state.code}
                                    onChange={this.handleChange} />
                            </Form.Group> 
                        </Row>
                            */}
                        {/* <Row className="justify-content-md-center">
                            <ButtonGroup size="lg flex">
                                <Button variant="outline-dark" onClick={() => this.addCode(1)}>1</Button>
                                <Button variant="outline-dark" onClick={() => this.addCode(2)}>2</Button>
                                <Button variant="outline-dark" onClick={() => this.addCode(3)}>3</Button>
                            </ButtonGroup>
                        </Row>
                        <Row className="justify-content-md-center">
                            <ButtonGroup size="lg flex">
                                <Button variant="outline-dark" onClick={() => this.addCode(4)}>4</Button>
                                <Button variant="outline-dark" onClick={() => this.addCode(5)}>5</Button>
                                <Button variant="outline-dark" onClick={() => this.addCode(6)}>6</Button>
                            </ButtonGroup>
                        </Row>
                        <Row className="justify-content-md-center">

                            <ButtonGroup size="lg flex">
                                <Button variant="outline-dark" onClick={() => this.addCode(7)}>7</Button>
                                <Button variant="outline-dark" onClick={() => this.addCode(8)}>8</Button>
                                <Button variant="outline-dark" onClick={() => this.addCode(9)}>9</Button>
                            </ButtonGroup>
                        </Row>
                        <Row className="justify-content-md-center">
                            <ButtonGroup size="lg flex">
                                <Button variant="outline-dark" onClick={() => this.addCode(0)}>0</Button>
                                <Button variant="outline-dark" onClick={() => this.addCode(-1)}>&lt;&lt;</Button>
                            </ButtonGroup>
                        </Row> */}
                        <Row>
                            <Form.Control
                                size="lg"
                                id="code"
                                name="email"
                                type="text"
                                placeholder="Code"
                                value={this.state.code}
                                onChange={this.handleChange} />
                            <Form.Control
                                size="lg"
                                id="teamCode"
                                type="password"
                                placeholder="Team Code"
                                value={this.state.teamCode}
                                onChange={this.handleChange} />
                            <Button size="lg" block variant="success" type="submit">Enter</Button>
                        </Row>
                    </Form>
                </Container >
            </DataContext.Provider>
        );
    }
}

